    add_paragraph(doc, 'Declaration\nCertificate\nAcknowledgements\nAbstract\nList of Tables\nList of Figures\nList of Abbreviations\n\nCHAPTER 1: INTRODUCTION\n1.1 BACKGROUND\n1.2 THE VALORANT ECOSYSTEM\n1.3 IDENTIFIED ISSUES/RESEARCH GAPS\n1.4 OBJECTIVE AND SCOPE\n1.5 PROJECT REPORT ORGANIZATION\n\nCHAPTER 2: LITERATURE REVIEW\n2.1 EVOLUTION OF SPORTS AND ESPORTS ANALYTICS\n2.2 MACHINE LEARNING IN COMPETITIVE GAMING\n2.3 EXISTING TECHNOLOGIES AND STRATEGIES\n2.4 THE ROLE OF NLP IN DATA ACCESSIBILITY\n\nCHAPTER 3: REQUIREMENTS AND ANALYSIS\n3.1 REQUIREMENTS SPECIFICATION\n3.2 PLANNING AND SCHEDULING\n3.3 SOFTWARE AND HARDWARE REQUIREMENTS\n3.4 PRELIMINARY PRODUCT DESCRIPTION\n\nCHAPTER 4: THEORETICAL FOUNDATIONS\n4.1 DATA MINING AND WEB SCRAPING THEORY\n4.2 FEATURE ENGINEERING THEORY\n4.3 ENSEMBLE LEARNING: RANDOM FORESTS\n4.4 GRADIENT BOOSTING MACHINES\n4.5 NATURAL LANGUAGE PROCESSING AND INTENT RECOGNITION\n\nCHAPTER 5: PROPOSED METHODOLOGY AND IMPLEMENTATION\n5.1 DATA INGESTION PIPELINE (EVENTS_SCRAPER)\n5.2 DATA CLEANING AND PREPROCESSING (PARQUET INTEGRATION)\n5.3 FEATURE ENGINEERING IMPLEMENTATION\n5.4 MACHINE LEARNING PIPELINE IMPLEMENTATION\n5.5 NLP CHATBOT INTEGRATION\n\nCHAPTER 6: RESULTS AND DISCUSSION\n6.1 MODEL EVALUATION METRICS\n6.2 FEATURE IMPORTANCE ANALYSIS\n6.3 PRACTICAL USABILITY AND SYSTEM LATENCY\n6.4 CASE STUDY: TEAM COMPOSITION SYNERGY\n\nCHAPTER 7: CONCLUSION AND FUTURE WORK\n7.1 CONCLUSION\n7.2 LIMITATIONS\n7.3 FUTURE ENHANCEMENTS\n\nREFERENCES\nAPPENDICES\nPUBLICATIONS\nPLAGIARISM REPORT\nCURRICULUM VITAE', size=12)
